// Helpers
COM.getPerfilById = function(id) {
  return COM.perfiles.find(p => p.id === id);
};

COM.getPreguntasAleatorias = function(perfilId, n = 8) {
  const pool = COM.preguntas[perfilId] || [];
  const shuffled = [...pool].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, n);
};
